import React from 'react';
import { CouponConfig } from '../types';

interface CouponProps {
  config: CouponConfig;
  serialNumber: number;
}

const Coupon: React.FC<CouponProps> = ({ config, serialNumber }) => {
  // Pad serial number with leading zeros (e.g., 0001)
  const paddedNumber = serialNumber.toString().padStart(6, '0');

  return (
    <div className="w-full h-48 border-[3px] border-double border-black p-1 flex flex-col bg-white overflow-hidden">
      <div className="border border-black p-3 h-full flex flex-col items-center justify-between">
        <div className="text-center">
          <h2 className="font-bold text-sm uppercase leading-tight">
            {config.companyName}
          </h2>
          <p className="text-xs font-medium">
            Số: <span className="font-bold">{paddedNumber}</span>
          </p>
        </div>

        <div className="text-center my-1">
          <h1 className="font-black text-xl uppercase italic">
            PHIẾU xăng {config.fuelType}
          </h1>
          <p className="text-sm font-bold uppercase mt-1">
            LOẠI: {config.volume} Lít ({config.volumeText})
          </p>
        </div>

        <div className="w-full flex justify-between items-end mt-2">
          <div className="text-[10px] italic">
            Ngày .........................
          </div>
          <div className="text-center">
            <p className="text-[11px] font-bold">{config.signatory}</p>
            <div className="h-8"></div> {/* Space for stamp/signature */}
          </div>
        </div>
      </div>
