};

export default Coupon;

import React, { useState, useCallback, useMemo } from 'react';
import { Printer, Settings, FileText, ChevronRight, LayoutGrid } from 'lucide-react';
import Coupon from './components/Coupon';
import { CouponConfig, FUEL_TYPES, VOLUME_OPTIONS, VolumeOption } from './types';

const App: React.FC = () => {
  const [config, setConfig] = useState<CouponConfig>({
    fromNumber: 1,
    toNumber: 8,
    fuelType: 'E5',
    volume: '04',
    volumeText: 'Bốn Lít',
    companyName: 'CÔNG TY XĂNG DẦU CHÂU THÀNH',
    signatory: 'P.Giám đốc'
  });

  const [isPreviewMode, setIsPreviewMode] = useState(true);

  const coupons = useMemo(() => {
    const list = [];
    for (let i = config.fromNumber; i <= config.toNumber; i++) {
      list.push(i);
    }
    return list;
  }, [config.fromNumber, config.toNumber]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    if (name === 'volume') {
      const selected = VOLUME_OPTIONS.find(v => v.value === value);
      if (selected) {
        setConfig(prev => ({
          ...prev,
          volume: selected.value,
          volumeText: selected.text
        }));
      }
    } else {
      setConfig(prev => ({
        ...prev,
        [name]: name.includes('Number') ? parseInt(value) || 0 : value
      }));
    }
  };

  const handlePrint = useCallback(() => {
    window.print();
  }, []);

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gray-100">
      {/* Sidebar Controls - Hidden on Print */}
      <aside className="no-print w-full md:w-80 bg-white shadow-xl p-6 overflow-y-auto sticky top-0 md:h-screen z-10">
        <div className="flex items-center gap-2 mb-8">
          <div className="p-2 bg-blue-600 rounded-lg">
            <Printer className="text-white w-6 h-6" />
          </div>
          <h1 className="text-xl font-bold text-gray-800">In Phiếu Xăng</h1>
        </div>

        <div className="space-y-6">
          <section>
            <h3 className="flex items-center gap-2 text-sm font-semibold text-gray-500 uppercase tracking-wider mb-4">
              <Settings className="w-4 h-4" /> Thông tin in phiếu
            </h3>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Từ số</label>
                <input
                  type="number"
                  name="fromNumber"
                  value={config.fromNumber}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Đến số</label>
                <input
                  type="number"
                  name="toNumber"
                  value={config.toNumber}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Loại Xăng</label>
                <select
                  name="fuelType"
                  value={config.fuelType}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition"
                >
                  {FUEL_TYPES.map(type => (
                    <option key={type} value={type}>{type}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Số lượng (Lít)</label>
                <select
                  name="volume"
                  value={config.volume}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition"
                >
                  {VOLUME_OPTIONS.map(opt => (
                    <option key={opt.value} value={opt.value}>{opt.label}</option>
                  ))}
                </select>
              </div>
            </div>
          </section>

          <section>
            <h3 className="flex items-center gap-2 text-sm font-semibold text-gray-500 uppercase tracking-wider mb-4">
              <LayoutGrid className="w-4 h-4" /> Tùy chỉnh đơn vị
            </h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Tên công ty</label>
                <input
                  type="text"
                  name="companyName"
                  value={config.companyName}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Chức vụ ký</label>
                <input
                  type="text"
                  name="signatory"
                  value={config.signatory}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition"
                />
              </div>
            </div>
          </section>

          <button
            onClick={handlePrint}
            className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-4 rounded-lg shadow-lg transform active:scale-95 transition"
          >
            <Printer className="w-5 h-5" /> In Phiếu Ngay
          </button>
        </div>

        <div className="mt-auto pt-8 text-xs text-gray-400 text-center">
          &copy; 2024 Gasoline Coupon System
        </div>
      </aside>

      {/* Main Preview Area */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto">
        <div className="no-print flex items-center justify-between mb-6">
          <div className="flex items-center gap-2 text-gray-600">
            <FileText className="w-5 h-5" />
            <span className="font-medium">Xem trước bản in (A4)</span>
          </div>
          <div className="text-sm bg-blue-50 text-blue-700 px-3 py-1 rounded-full border border-blue-100 font-medium">
            Tổng số phiếu: {coupons.length}
          </div>
        </div>

        {/* The Paper Component */}
        <div className="print-page mx-auto bg-white shadow-2xl origin-top transition-all duration-300" 
             style={{ width: '210mm', minHeight: '297mm', padding: '10mm' }}>

          {/* Grid Layout for A4 */}
          <div className="grid grid-cols-2 gap-4">
            {coupons.map((num) => (
              <Coupon key={num} config={config} serialNumber={num} />
            ))}
          </div>

          {coupons.length === 0 && (
            <div className="flex flex-col items-center justify-center h-96 text-gray-300 border-2 border-dashed border-gray-200 rounded-lg">
              <FileText className="w-16 h-16 mb-4" />
              <p className="text-xl font-medium">Chưa có phiếu nào được tạo</p>
              <p className="text-sm">Hãy nhập dải số ở cột bên trái</p>
            </div>
          )}
        </div>
      </main>

      {/* Sticky Mobile Print Button */}
      <div className="no-print md:hidden fixed bottom-6 right-6">
        <button
          onClick={handlePrint}
          className="bg-blue-600 text-white p-4 rounded-full shadow-2xl flex items-center justify-center"
        >
          <Printer className="w-6 h-6" />
        </button>
      </div>
    </div>
  );
};

export default App;

