    // Giới hạn hiển thị 10 phiếu trên 1 trang A4 (2x5) theo yêu cầu mẫu
    const limit = 10;
    for (let i = from; i <= Math.min(to, from + limit - 1); i++) {
      list.push(i);
    }
    return list;
