    // Giới hạn 10 phiếu trên 1 trang (theo yêu cầu layout 2 cột x 5 hàng)
    const limit = 10;
    for (let i = from; i <= Math.min(to, from + limit - 1); i++) {
      list.push(i);
    }
    return list;
