import React, { useState, useCallback, useMemo } from 'react';
import { Printer, Settings, FileText, LayoutGrid, Eye, ZoomIn, ZoomOut, Type } from 'lucide-react';
import Coupon from './components/Coupon';
import { CouponConfig, FUEL_TYPES, VOLUME_OPTIONS, FONT_OPTIONS } from './types';

const App: React.FC = () => {
  const [config, setConfig] = useState<CouponConfig>({
    fromNumber: 1,
    toNumber: 10,
    fuelType: 'E5',
    volume: '04',
    volumeText: 'Bốn Lít',
    companyName: 'CÔNG TY XĂNG DẦU CHÂU THÀNH',
    signatory: 'P.Giám đốc',
    fontFamily: "'Inter', sans-serif"
  });

  const [zoom, setZoom] = useState(0.8);

  // Logic chia trang: Mỗi trang chứa tối đa 10 phiếu
  const pages = useMemo(() => {
    const from = Math.min(config.fromNumber, config.toNumber);
    const to = Math.max(config.fromNumber, config.toNumber);
    const allNumbers = [];

    for (let i = from; i <= to; i++) {
      allNumbers.push(i);
    }

    const chunks = [];
    const pageSize = 10;
    for (let i = 0; i < allNumbers.length; i += pageSize) {
      chunks.push(allNumbers.slice(i, i + pageSize));
    }
    return chunks;
  }, [config.fromNumber, config.toNumber]);

  const totalCoupons = useMemo(() => {
    const from = Math.min(config.fromNumber, config.toNumber);
    const to = Math.max(config.fromNumber, config.toNumber);
