import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Printer, Settings, FileText, LayoutGrid, Eye, ZoomIn, ZoomOut, Type, ChevronLeft, ChevronRight, Loader2 } from 'lucide-react';
import Coupon from './components/Coupon';
import { CouponConfig, FUEL_TYPES, VOLUME_OPTIONS, FONT_OPTIONS } from './types';

const App: React.FC = () => {
  const [config, setConfig] = useState<CouponConfig>({
    fromNumber: 1,
    toNumber: 10,
    fuelType: 'E5',
    volume: '04',
    volumeText: 'Bốn Lít',
    companyName: 'CÔNG TY XĂNG DẦU CHÂU THÀNH',
    signatory: 'P.Giám đốc',
    fontFamily: "'Times New Roman', Times, serif"
  });

  const [zoom, setZoom] = useState(0.8);
  const [currentPageIndex, setCurrentPageIndex] = useState(0);
  const [isPrinting, setIsPrinting] = useState(false);

  // Logic chia trang: Mỗi trang chứa tối đa 10 phiếu
  const pages = useMemo(() => {
    const from = Math.min(config.fromNumber, config.toNumber);
    const to = Math.max(config.fromNumber, config.toNumber);
    const allNumbers = [];

    for (let i = from; i <= to; i++) {
      allNumbers.push(i);
    }

    const chunks = [];
    const pageSize = 10;
    for (let i = 0; i < allNumbers.length; i += pageSize) {
      chunks.push(allNumbers.slice(i, i + pageSize));
    }
    return chunks;
  }, [config.fromNumber, config.toNumber]);

  // Reset về trang 1 nếu tổng số trang thay đổi
  useEffect(() => {
    if (currentPageIndex >= pages.length) {
      setCurrentPageIndex(0);
    }
  }, [pages.length, currentPageIndex]);

  const totalCoupons = useMemo(() => {
    const from = Math.min(config.fromNumber, config.toNumber);
    const to = Math.max(config.fromNumber, config.toNumber);
    return to - from + 1;
  }, [config.fromNumber, config.toNumber]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    if (name === 'volume') {
      const selected = VOLUME_OPTIONS.find(v => v.value === value);
      if (selected) {
        setConfig(prev => ({
          ...prev,
          volume: selected.value,
          volumeText: selected.text
        }));
      }
    } else {
      setConfig(prev => ({
        ...prev,
        [name]: name.includes('Number') ? (parseInt(value) || 0) : value
      }));
    }
  };

  const handlePrint = useCallback(() => {
    setIsPrinting(true);
    // Đợi một chút để UI cập nhật trạng thái loading trước khi gọi lệnh in hệ thống
    setTimeout(() => {
      window.print();
      setIsPrinting(false);
    }, 500);
  }, []);

  const goToNextPage = () => {
    if (currentPageIndex < pages.length - 1) {
      setCurrentPageIndex(currentPageIndex + 1);
    }
  };

  const goToPrevPage = () => {
    if (currentPageIndex > 0) {
      setCurrentPageIndex(currentPageIndex - 1);
    }
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-slate-50 overflow-hidden">
      {/* Sidebar điều khiển */}
      <aside className="no-print w-full lg:w-96 bg-white shadow-2xl p-6 overflow-y-auto lg:h-screen z-10 shrink-0 border-r border-slate-200">
        <div className="flex items-center gap-3 mb-8">
          <div className="p-2.5 bg-blue-600 rounded-xl shadow-lg">
            <Printer className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-black leading-none">In Phiếu Xăng</h1>
            <p className="text-[10px] text-slate-700 font-bold uppercase mt-1 tracking-wider">Phiên bản chuyên nghiệp</p>
          </div>
        </div>

        <div className="space-y-6 pb-10">
          <section className="bg-slate-50 p-4 rounded-xl border border-slate-200">
            <h3 className="flex items-center gap-2 text-xs font-bold text-black uppercase tracking-widest mb-4">
              <Eye className="w-4 h-4" /> Xem trước mẫu
            </h3>
            <div className="flex justify-center overflow-hidden scale-[0.75] origin-top bg-white border">
              <Coupon config={config} serialNumber={config.fromNumber} />
            </div>
          </section>

          <section className="space-y-4">
            <h3 className="flex items-center gap-2 text-xs font-bold text-black uppercase tracking-widest mb-2">
              <Type className="w-4 h-4" /> Kiểu chữ
            </h3>
            <div>
              <select
                name="fontFamily"
                value={config.fontFamily}
                onChange={handleInputChange}
                className="w-full px-4 py-2 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-black cursor-pointer"
              >
                {FONT_OPTIONS.map(opt => (
                  <option key={opt.value} value={opt.value}>{opt.label}</option>
                ))}
              </select>
            </div>
          </section>

          <section className="space-y-4">
            <h3 className="flex items-center gap-2 text-xs font-bold text-black uppercase tracking-widest mb-2">
              <Settings className="w-4 h-4" /> Dãy số thứ tự
            </h3>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[11px] font-bold text-black uppercase">Từ số</label>
                <input
                  type="number"
                  name="fromNumber"
                  value={config.fromNumber}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-black bg-white"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[11px] font-bold text-black uppercase">Đến số</label>
                <input
                  type="number"
                  name="toNumber"
                  value={config.toNumber}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-black bg-white"
                />
              </div>
            </div>
          </section>

          <section className="space-y-4">
            <h3 className="flex items-center gap-2 text-xs font-bold text-black uppercase tracking-widest mb-2">
              <LayoutGrid className="w-4 h-4" /> Nội dung phiếu
            </h3>
            <div className="space-y-3">
              <div>
                <label className="block text-[11px] font-bold text-black uppercase mb-1">Loại Xăng</label>
                <select
                  name="fuelType"
                  value={config.fuelType}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-black cursor-pointer"
                >
                  {FUEL_TYPES.map(type => (
                    <option key={type} value={type}>{type}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-[11px] font-bold text-black uppercase mb-1">Định mức</label>
                <select
                  name="volume"
                  value={config.volume}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-black cursor-pointer"
                >
                  {VOLUME_OPTIONS.map(opt => (
                    <option key={opt.value} value={opt.value}>{opt.label}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-[11px] font-bold text-black uppercase mb-1">Đơn vị ban hành</label>
                <input
                  type="text"
                  name="companyName"
                  value={config.companyName}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-black bg-white"
                />
              </div>
              <div>
                <label className="block text-[11px] font-bold text-black uppercase mb-1">Chức vụ ký</label>
                <input
                  type="text"
                  name="signatory"
                  value={config.signatory}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-black bg-white"
                />
              </div>
            </div>
          </section>

          <button
            onClick={handlePrint}
            disabled={isPrinting}
            className={`w-full flex items-center justify-center gap-3 font-bold py-4 rounded-xl shadow-lg active:scale-95 transition-all ${
              isPrinting ? 'bg-slate-400 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700 text-white'
            }`}
          >
            {isPrinting ? <Loader2 className="w-6 h-6 animate-spin" /> : <Printer className="w-6 h-6" />}
            <div className="text-left">
               <div className="text-sm uppercase">{isPrinting ? 'Đang chuẩn bị...' : 'In toàn bộ'}</div>
               {!isPrinting && <div className="text-[9px] opacity-70">Tổng {totalCoupons} phiếu ({pages.length} trang)</div>}
            </div>
          </button>
        </div>
      </aside>

      {/* Vùng hiển thị trang giấy A4 */}
      <main className="flex-1 p-4 lg:p-8 overflow-y-auto flex flex-col items-center bg-slate-200 relative">
        <div className="no-print w-full max-w-[210mm] flex flex-col gap-4 mb-6">
          <div className="w-full flex items-center justify-between px-6 py-3 bg-white/90 backdrop-blur shadow-sm rounded-full border border-white">
            <div className="flex items-center gap-3 text-black font-bold text-xs uppercase tracking-tight">
              <FileText className="w-4 h-4 text-blue-500" />
              <span>Xem trước: Trang {currentPageIndex + 1} / {pages.length}</span>
            </div>

            <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 border-r border-slate-200 pr-4">
                <button onClick={() => setZoom(z => Math.max(0.4, z - 0.1))} className="p-1.5 hover:bg-slate-100 rounded-full transition-colors"><ZoomOut className="w-5 h-5 text-black" /></button>
                <span className="text-xs font-bold w-12 text-center text-black">{Math.round(zoom * 100)}%</span>
                <button onClick={() => setZoom(z => Math.min(1.5, z + 0.1))} className="p-1.5 hover:bg-slate-100 rounded-full transition-colors"><ZoomIn className="w-5 h-5 text-black" /></button>
              </div>
              <button 
                onClick={handlePrint} 
                className="bg-blue-600 text-white px-5 py-2 rounded-full text-xs font-bold hover:bg-blue-700 transition-all shadow-md active:scale-95 flex items-center gap-2"
              >
                {isPrinting && <Loader2 className="w-3 h-3 animate-spin" />}
                MỞ LỆNH IN
              </button>
            </div>
          </div>

          {/* Thanh phân trang Pagination */}
          {pages.length > 1 && (
            <div className="w-full flex justify-center">
              <nav className="flex items-center gap-1 bg-white p-1.5 rounded-xl shadow-sm border border-slate-200">
                <button 
                  onClick={goToPrevPage}
                  disabled={currentPageIndex === 0}
                  className={`p-2 rounded-lg transition-all ${currentPageIndex === 0 ? 'text-slate-300 cursor-not-allowed' : 'text-slate-600 hover:bg-slate-100'}`}
                >
                  <ChevronLeft className="w-5 h-5" />
                </button>

                <div className="flex items-center gap-1 px-2 overflow-x-auto max-w-[400px]">
                  {pages.map((_, idx) => (
                    <button
                      key={idx}
                      onClick={() => setCurrentPageIndex(idx)}
                      className={`min-w-[36px] h-9 rounded-lg text-sm font-bold transition-all ${
                        currentPageIndex === idx 
                          ? 'bg-blue-600 text-white shadow-md' 
                          : 'text-slate-600 hover:bg-slate-100'
                      }`}
                    >
                      {idx + 1}
                    </button>
                  ))}
                </div>

                <button 
                  onClick={goToNextPage}
                  disabled={currentPageIndex === pages.length - 1}
                  className={`p-2 rounded-lg transition-all ${currentPageIndex === pages.length - 1 ? 'text-slate-300 cursor-not-allowed' : 'text-slate-600 hover:bg-slate-100'}`}
                >
                  <ChevronRight className="w-5 h-5" />
                </button>
              </nav>
            </div>
          )}
        </div>

        {/* CONTAINER HIỂN THỊ TRÊN MÀN HÌNH (Chỉ 1 trang hiện tại) */}
        <div className="no-print flex flex-col items-center">
          {pages[currentPageIndex] && (
            <div 
              className="bg-white shadow-2xl box-border overflow-hidden origin-top transition-transform" 
              style={{ 
                width: '210mm', 
                height: '297mm', 
                padding: '15mm 10mm',
                transform: `scale(${zoom})`,
                marginBottom: `calc(${zoom * 297}mm - 297mm + 40px)`
              }}
            >
              <div className="grid grid-cols-2 gap-x-[10mm] gap-y-[6mm] justify-center">
                {pages[currentPageIndex].map((num) => (
                  <div key={num} className="coupon-item">
                    <Coupon config={config} serialNumber={num} />
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* CONTAINER ẨN ĐỂ IN (Chứa tất cả các trang) - Sử dụng style inline để tránh bị class Tailwind hidden chặn hoàn toàn */}
        <div className="hidden-on-screen-only" style={{ display: 'none' }}>
          {pages.map((pageCoupons, pageIndex) => (
            <div 
              key={pageIndex}
              className="print-page bg-white" 
            >
              <div className="grid grid-cols-2 gap-x-[10mm] gap-y-[6mm] justify-center">
                {pageCoupons.map((num) => (
                  <div key={num} className="coupon-item">
                    <Coupon config={config} serialNumber={num} />
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>

        <style>{`
          @media print {
            .hidden-on-screen-only {
              display: block !important;
            }
          }
        `}</style>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Printer, Settings, FileText, LayoutGrid, Eye, ZoomIn, ZoomOut, Type, ChevronLeft, ChevronRight, Loader2 } from 'lucide-react';
