              <LayoutGrid className="w-4 h-4" /> Nội dung in
            </h3>
            <div className="space-y-3">
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1">Loại xăng</label>
                <select name="fuelType" value={config.fuelType} onChange={handleInputChange} className="w-full px-3 py-2 border border-slate-300 rounded-lg font-bold">
